property.value:
//JumpExpression[
    (T-BREAK or T-CONTINUE or T-RETURN)
    and (ancestor::ForStatement or ancestor::WhileStatement or ancestor::DoWhileStatement)
    and not(ancestor::IfExpression[
        ancestor::ForStatement or ancestor::WhileStatement or ancestor::DoWhileStatement
    ])
    and not(ancestor::WhenExpression[
        ancestor::ForStatement or ancestor::WhileStatement or ancestor::DoWhileStatement
    ])
    and not(ancestor::ElvisExpression[
        Elvis
        and (ancestor::ForStatement or ancestor::WhileStatement or ancestor::DoWhileStatement)
    ])
    and not(ancestor::LambdaLiteral[
        ancestor::ForStatement or ancestor::WhileStatement or ancestor::DoWhileStatement
    ])
    and not(ancestor::AnonymousFunction[
        ancestor::ForStatement or ancestor::WhileStatement or ancestor::DoWhileStatement
    ])
]

rule.example:
// violation: the loop always executes exactly once
fun first(list: List<Int>): Int? {
    for (i in list) {
        return i  // should be: if (condition) { return i }
    }
    return null
}

// ok: break is guarded by an if
fun findFirst(list: List<Int>, target: Int) {
    for (i in list) {
        if (i == target) {
            break
        }
    }
}

class Bad {
    fun close(res: Resource) {
        res.finalize() // violation: explicit finalize() call
    }
}

class Good {
    fun process(res: AutoCloseable) {
        res.use { /* work with res */ } // ok: idiomatic Kotlin resource management
    }
}

class Bad {
    fun handle() {
        try {
            riskyOp()
        } catch (e: Exception) { // violation: too broad
            log.error("failed", e)
        }
    }
}

class Good {
    fun handle() {
        try {
            riskyOp()
        } catch (e: IOException) { // ok: specific exception
            log.error("io error", e)
        }
    }

    fun handleKotlinStyle() {
        runCatching { riskyOp() }.onFailure { log.error("failed", it) } // ok: idiomatic
    }
}

class Bad {
    fun getLength(s: String?): Int {
        return try {
            s!!.length
        } catch (e: NullPointerException) { // violation: use ?. instead
            0
        }
    }
}

class Good {
    fun getLength(s: String?): Int {
        return s?.length ?: 0  // ok: idiomatic Kotlin null-safety
    }
}

class Bad {
    fun handle() {
        try {
            riskyOp()
        } catch (e: Throwable) { // violation: catches Errors too
            log.error("failed", e)
        }
    }
}

class Good {
    fun handle() {
        try {
            riskyOp()
        } catch (e: Exception) { // ok: only catches exceptions, not errors
            log.error("failed", e)
        }
    }

    fun handleKotlinStyle() {
        runCatching { riskyOp() }.onFailure { log.error("failed", it) } // ok: idiomatic, handles non-fatal exceptions only
    }
}

class Bad {
    private val numFormat: DecimalFormat = DecimalFormat("###.###") // violation

    companion object {
        val NUMBER_FORMAT: DecimalFormat = DecimalFormat("###.###") // violation
    }
}

class Good {
    fun format(value: Double): String {
        val fmt = DecimalFormat("###.###") // ok: local variable
        return fmt.format(value)
    }
}

import java.math.BigDecimal

class Bad {
    fun calc() {
        val a = BigDecimal(0.1)   // violation: imprecise due to floating-point
        val b = BigDecimal(0.1f)  // violation: same issue with float
    }
}

class Good {
    fun calc() {
        val a = BigDecimal("0.1")          // ok: exact string representation
        val b = BigDecimal.valueOf(0.1)    // ok: uses canonical double string
        val c = "0.1".toBigDecimal()       // ok: idiomatic Kotlin extension
    }
}

property.value:
//CatchBlock[
    count(Block/Statements/Statement) = 1
    and not(pmd-kotlin:typeIs('java.util.concurrent.CancellationException'))
    and Block//JumpExpression[
        T-THROW
        and .//PrimaryExpression[
            @Identifier = ancestor::CatchBlock/@Identifier
            and not(ancestor::ValueArguments)
        ]
    ]
]

rule.example:
// violation: catch that only rethrows adds no value
fun bad() {
    try {
        risky()
    } catch (e: IllegalStateException) {
        throw e
    }
}

// ok: catch that logs before rethrowing
fun good() {
    try {
        risky()
    } catch (e: IllegalStateException) {
        logger.error("operation failed", e)
        throw e
    }
}

// violation: explicitly throwing NPE is confusing
fun bad(value: String?) {
    if (value == null) throw NullPointerException("value must not be null")
}

// ok: use Kotlin idiomatic null checks
fun good(value: String?) {
    requireNotNull(value) { "value must not be null" }
}

// violation: raw exception types carry no semantic information
fun bad(input: String) {
    if (input.isEmpty()) throw Exception("input is empty")
    if (input.length > 100) throw RuntimeException("too long")
}

// ok: specific exception type communicates the failure reason
fun good(input: String) {
    if (input.isEmpty()) throw IllegalArgumentException("input is empty")
    if (input.length > 100) throw IllegalArgumentException("input exceeds 100 characters")
}

// violation: Error subclasses bypass catch(e: Exception)
class MyError : Error("something went wrong")
class MyAssertError : AssertionError("assertion failed")

// ok: proper exception hierarchy
class MyException : RuntimeException("something went wrong")
class MyCheckedException : Exception("checked equivalent")

class Bad {
    fun shutdown(code: Int) {
        System.exit(code)  // violation: abrupt JVM termination
    }
}

class Good {
    fun shutdown(code: Int): Nothing {
        throw IllegalStateException("shutdown requested with code $code")  // ok: exception-based
    }
}

class Bad {
    fun check(s: String?) {
        if (s.equals(null)) println("null")  // violation
    }
}

class Good {
    fun check(s: String?) {
        if (s == null) println("null")  // ok: idiomatic Kotlin null check
    }
}

class Bar {        // poor, missing a hashCode() method
    override fun equals(o: Any?): Boolean {
      // do some comparison
    }
}

class Baz {        // poor, missing an equals() method
    override fun hashCode(): Int {
      // return some hash value
    }
}

class Foo {        // ok: both methods provided
    override fun equals(other: Any?): Boolean {
      // do some comparison
    }
    override fun hashCode(): Int {
      // return some hash value
    }
}

data class Point(val x: Int, val y: Int)  // idiomatic Kotlin: data class auto-generates equals() and hashCode()

import java.util.Date

class Bad {
    val created: Date = Date()               // violation
    val fromMillis: Date = Date(1000L)       // violation
}

class Good {
    val created = java.time.Instant.now()    // ok: use java.time.Instant for timestamps
    val date = java.time.LocalDate.now()     // ok: use java.time.LocalDate for dates
}

import java.util.List

class Bad {
    // violation: returns null instead of an empty collection
    fun getItems(): List<String>? {
        return null
    }

    // violation: expression body
    fun getConfig(): List<String>? = null
}

class Good {
    // ok: return an empty collection
    fun getItems(): List<String>? {
        return emptyList()
    }

    // ok: return null from a non-collection nullable type is fine
    fun getLabel(): String? {
        return null
    }
}

class Bad {
    fun load(): Int {
        try {
            return 1
        } finally {
            return 2  // violation: silently discards any exception from the try block
        }
    }
}

class Good {
    fun load(): Int {
        try {
            return 1
        } finally {
            cleanup()  // ok: no return in finally
        }
    }

    private fun cleanup() {}
}

import java.text.SimpleDateFormat
import java.util.Locale

class Bad {
    val formatter = SimpleDateFormat("yyyy-MM-dd")  // violation: no Locale
}

class Good {
    val formatter = SimpleDateFormat("yyyy-MM-dd", Locale.US)  // ok: explicit Locale

    // Better: use java.time APIs
    val dtFormatter = java.time.format.DateTimeFormatter.ofPattern("yyyy-MM-dd", Locale.US)
}

class Bad {
    fun check(input: String, expected: String): Boolean {
        return input.toLowerCase().equals(expected)  // violation: creates a temporary String
    }
}

class Good {
    fun check(input: String, expected: String): Boolean {
        return input.equals(expected, ignoreCase = true)  // ok: no temporary String
    }
}

// Assume com.example.missing is not on the PMD classpath:
import com.example.missing.SomeClass   // violation: UnresolvedType

import java.util.Date                  // ok: java.util is always resolvable

class Bad {
    fun normalize(s: String): String {
        return s.toLowerCase()   // violation: system-locale dependent
    }

    fun shout(s: String): String {
        return s.toUpperCase()   // violation: system-locale dependent
    }
}

class Good {
    fun normalize(s: String): String {
        return s.lowercase()   // ok: Kotlin extension, uses Locale.ROOT
    }

    fun shout(s: String): String {
        return s.uppercase()   // ok: Kotlin extension, uses Locale.ROOT
    }

    fun displayLabel(s: String): String {
        return s.lowercase(java.util.Locale.getDefault())  // ok: explicit locale for UI
    }
}
